async (params, browser) => {
  // Open Google News
  await browser.open('https://news.google.com/')

  // Wait for content to load
  await browser.waitForSelector('article, c-wiz article, [data-n-tid]', 15000)

  // Let page settle
  await browser.wait(2500)

  // Scroll to find trending section
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Continue scrolling for more stories
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract trending stories
  const trending_data = await browser.evaluate(`const trending = []; const items = document.querySelectorAll('article, c-wiz article'); const seen = new Set(); for (let i = 0; i < items.length && trending.length < 20; i++) { const item = items[i]; const linkEl = item.querySelector('a[href*="./articles/"], a[href*="./read/"], a[href^="https"]'); const titleEl = linkEl ? linkEl.querySelector('h3, h4, .JtKRv') || linkEl : null; const title = titleEl ? titleEl.textContent.trim() : ''; if (!title || seen.has(title)) continue; seen.add(title); const sourceEl = item.querySelector('.vr1PYe, [data-n-tid], .wsn2rd, div > div > a[data-n-tid]'); const timeEl = item.querySelector('time, .hvbAAd, datetime'); let url = ''; if (linkEl) { const href = linkEl.getAttribute('href') || ''; if (href.startsWith('./')) { url = 'https://news.google.com/' + href.slice(2); } else if (href.startsWith('http')) { url = href; } else { url = 'https://news.google.com/' + href; } } const relatedCount = item.querySelectorAll('a[href*="./articles/"], a[href*="./read/"]').length; trending.push({ title: title, source: sourceEl ? sourceEl.textContent.trim() : '', time: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '', url: url, related_articles: relatedCount > 1 ? relatedCount - 1 : 0 }); } return { source: 'Google News - Trending', trending_count: trending.length, trending: trending }`)

  return trending_data
}
